content:
{
  "sentences": [
    {
      "text": "我房間的冷氣壞掉了，房東說明天會來修理。",
      "pinyin": "Wǒ fángjiān de lěngqì huài diào le, fángdōng shuō míngtiān huì lái xiūlǐ.",
      "pinyin_numeric": "wo3 fang2jian1 de0 leng3qi4 huai4 diao4 le0, fang2dong1 shuo1 ming2tian1 hui4 lai2 xiu1li3.",
      "translation_en": "The air conditioner in my room is broken; the landlord said he will come to fix it tomorrow.",
      "translation_ko": "제 방의 에어컨이 고장 났는데, 집주인이 내일 와서 고쳐 주겠다고 했어요."
    },
    {
      "text": "客廳的燈壞掉了，所以我們晚上都用桌燈。",
      "pinyin": "Kètīng de dēng huài diào le, suǒyǐ wǒmen wǎnshàng dōu yòng zhuōdēng.",
      "pinyin_numeric": "ke4ting1 de0 deng1 huai4 diao4 le0, suo3yi3 wo3men wan3shang4 dou1 yong4 zhuo1deng1.",
      "translation_en": "The light in the living room is broken, so we use a desk lamp at night.",
      "translation_ko": "거실의 불이 고장 나서, 우리는 밤에 책상 램프를 사용해요."
    },
    {
      "text": "浴室的熱水器壞掉了，我必須用冷水洗澡。",
      "pinyin": "Yùshì de rèshuǐqì huài diào le, wǒ bìxū yòng lěngshuǐ xǐzǎo.",
      "pinyin_numeric": "yu4shi4 de0 re4shui3qi4 huai4 diao4 le0, wo3 bi4xu1 yong4 leng3shui3 xi3zao3.",
      "translation_en": "The water heater in the bathroom is broken, so I have to take a cold shower.",
      "translation_ko": "욕실의 온수기가 고장 나서, 찬물로 샤워해야 해요."
    },
    {
      "text": "廚房的冰箱壞掉了，裡面的食物都壞了。",
      "pinyin": "Chúfáng de bīngxiāng huài diào le, lǐmiàn de shíwù dōu huài le.",
      "pinyin_numeric": "chu2fang2 de0 bing1xiang1 huai4 diao4 le0, li3mian4 de0 shi2wu4 dou1 huai4 le0.",
      "translation_en": "The refrigerator in the kitchen is broken, and the food inside has gone bad.",
      "translation_ko": "부엌의 냉장고가 고장 나서, 안에 있던 음식이 모두 상했어요."
    },
    {
      "text": "陽台的門壞掉了，所以風一直吹進來。",
      "pinyin": "Yángtái de mén huài diào le, suǒyǐ fēng yīzhí chuī jìnlái.",
      "pinyin_numeric": "yang2tai2 de0 men2 huai4 diao4 le0, suo3yi3 feng1 yi1zhi2 chui1 jin4lai2.",
      "translation_en": "The balcony door is broken, so the wind keeps blowing in.",
      "translation_ko": "발코니 문이 고장 나서, 바람이 계속 들어와요."
    },
    {
      "text": "客廳的沙發壞掉了，坐起來很不舒服。",
      "pinyin": "Kètīng de shāfā huài diào le, zuò qǐlái hěn bù shūfú.",
      "pinyin_numeric": "ke4ting1 de0 sha1fa1 huai4 diao4 le0, zuo4 qi3lai2 hen3 bu4 shu1fu2.",
      "translation_en": "The sofa in the living room is broken, and it's very uncomfortable to sit on.",
      "translation_ko": "거실의 소파가 고장 나서, 앉기가 매우 불편해요."
    },
    {
      "text": "浴室的馬桶壞掉了，我已經打電話請房東修理。",
      "pinyin": "Yùshì de mǎtǒng huài diào le, wǒ yǐjīng dǎ diànhuà qǐng fángdōng xiūlǐ.",
      "pinyin_numeric": "yu4shi4 de0 ma3tong3 huai4 diao4 le0, wo3 yi3jing1 da3 dian4hua4 qing3 fang2dong1 xiu1li3.",
      "translation_en": "The toilet in the bathroom is broken; I've already called the landlord to fix it.",
      "translation_ko": "욕실의 변기가 고장 나서, 이미 집주인에게 전화해서 수리를 요청했어요."
    },
    {
      "text": "廚房的洗衣機壞掉了，所以我今天用手洗衣服。",
      "pinyin": "Chúfáng de xǐyījī huài diào le, suǒyǐ wǒ jīntiān yòng shǒu xǐ yīfú.",
      "pinyin_numeric": "chu2fang2 de0 xi3yi1ji1 huai4 diao4 le0, suo3yi3 wo3 jin1tian1 yong4 shou3 xi3 yi1fu2.",
      "translation_en": "The washing machine in the kitchen is broken, so I'm washing clothes by hand today.",
      "translation_ko": "부엌의 세탁기가 고장 나서, 오늘은 손으로 빨래를 해요."
    },
    {
      "text": "房間的窗戶壞掉了，打不開也關不起來。",
      "pinyin": "Fángjiān de chuānghù huài diào le, dǎ bù kāi yě guān bù qǐlái.",
      "pinyin_numeric": "fang2jian1 de0 chuang1hu4 huai4 diao4 le0, da3 bu4 kai1 ye3 guan1 bu4 qi3lai2.",
      "translation_en": "The window in the room is broken; it won't open or close.",
      "translation_ko": "방의 창문이 고장 나서, 열리지도 않고 닫히지도 않아요."
    },
    {
      "text": "客廳的電視壞掉了，我們現在都用手機看電影。",
      "pinyin": "Kètīng de diànshì huài diào le, wǒmen xiànzài dōu yòng shǒujī kàn diànyǐng.",
      "pinyin_numeric": "ke4ting1 de0 dian4shi4 huai4 diao4 le0, wo3men xian4zai4 dou1 yong4 shou3ji1 kan4 dian4ying3.",
      "translation_en": "The TV in the living room is broken, so we now watch movies on our phones.",
      "translation_ko": "거실의 TV가 고장 나서, 우리는 지금 핸드폰으로 영화를 봐요."
    }
  ]
}
